INSERT INTO nodes (id, campaign_id, type_id, title, fields) VALUES
  ('4dc2fedd-c3f0-5ab4-9b82-58045a694e06', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000006', 'Goblin', '{"name": "Goblin", "source_doc": "SRD 2014 (Open5e)", "cr": "1/4", "type": "humanoid", "size": "small", "alignment": "neutral evil", "ac": 15, "ac_detail": "leather armor, shield", "hp": 7, "hit_dice": "2d6", "speed": {"walk": 30}, "stats": {"str": 8, "dex": 14, "con": 10, "int": 10, "wis": 8, "cha": 8}, "saves": {}, "skills": {"stealth": 6}, "senses": {"passive_perception": 9, "darkvision": 60}, "languages": "Common, Goblin", "resistances": "", "immunities": "", "vulnerabilities": "", "condition_immunities": "", "proficiency_bonus": null, "actions": [{"name": "Scimitar", "desc": "Melee Weapon Attack: +4 to hit, reach 5 ft., one target. Hit: 5 (1d6 + 2) slashing damage.", "targeting": "single", "source": null}, {"name": "Shortbow", "desc": "Ranged Weapon Attack: +4 to hit, range 80/320 ft., one target. Hit: 5 (1d6 + 2) piercing damage.", "targeting": "single", "source": null}], "bonus_actions": [{"name": "Nimble Escape", "desc": "The goblin can take the Disengage or Hide action as a bonus action on each of its turns.", "source": null, "targeting": "single"}], "reactions": [], "legendary_actions": [], "legendary_budget": 0, "passives": [], "tags": ["srd", "canon", "humanoid"]}'::jsonb),
  ('4470f47e-4af7-53a2-91d3-2ad0c2178b5d', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000006', 'Orc', '{"name": "Orc", "source_doc": "SRD 2014 (Open5e)", "cr": "1/2", "type": "humanoid", "size": "medium", "alignment": "chaotic evil", "ac": 13, "ac_detail": "hide armor", "hp": 15, "hit_dice": "2d8+6", "speed": {"walk": 30}, "stats": {"str": 16, "dex": 12, "con": 16, "int": 7, "wis": 11, "cha": 10}, "saves": {}, "skills": {"intimidation": 2}, "senses": {"passive_perception": 10, "darkvision": 60}, "languages": "Common, Orc", "resistances": "", "immunities": "", "vulnerabilities": "", "condition_immunities": "", "proficiency_bonus": null, "actions": [{"name": "Greataxe", "desc": "Melee Weapon Attack: +5 to hit, reach 5 ft., one target. Hit: 9 (1d12 + 3) slashing damage.", "targeting": "single", "source": null}, {"name": "Javelin", "desc": "Melee or Ranged Weapon Attack: +5 to hit, reach 5 ft. or range 30/120 ft., one target. Hit: 6 (1d6 + 3) piercing damage.", "targeting": "single", "source": null}], "bonus_actions": [{"name": "Aggressive", "desc": "As a bonus action, the orc can move up to its speed toward a hostile creature that it can see.", "source": null, "targeting": "single"}], "reactions": [], "legendary_actions": [], "legendary_budget": 0, "passives": [], "tags": ["srd", "canon", "humanoid"]}'::jsonb),
  ('3839540c-bdc6-5d84-b814-6c1bb0d10365', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000006', 'Giant Spider', '{"name": "Giant Spider", "source_doc": "SRD 2014 (Open5e)", "cr": "1", "type": "beast", "size": "large", "alignment": "unaligned", "ac": 14, "ac_detail": "natural armor", "hp": 26, "hit_dice": "4d10+4", "speed": {"walk": 30, "climb": 30}, "stats": {"str": 14, "dex": 16, "con": 12, "int": 2, "wis": 11, "cha": 4}, "saves": {}, "skills": {"stealth": 7}, "senses": {"passive_perception": 10, "darkvision": 60, "blindsight": 10}, "languages": "", "resistances": "", "immunities": "", "vulnerabilities": "", "condition_immunities": "", "proficiency_bonus": null, "actions": [{"name": "Bite", "desc": "Melee Weapon Attack: +5 to hit, reach 5 ft., one creature. Hit: 7 (1d8 + 3) piercing damage, and the target must make a DC 11 Constitution saving throw, taking 9 (2d8) poison damage on a failed save, or half as much damage on a successful one. If the poison damage reduces the target to 0 hit points, the target is stable but poisoned for 1 hour, even after regaining hit points, and is paralyzed while poisoned in this way.", "targeting": "single", "source": null}, {"name": "Web", "desc": "Ranged Weapon Attack: +5 to hit, range 30/60 ft., one creature. Hit: The target is restrained by webbing. As an action, the restrained target can make a DC 12 Strength check, bursting the webbing on a success. The webbing can also be attacked and destroyed (AC 10; hp 5; vulnerability to fire damage; immunity to bludgeoning, poison, and psychic damage).", "targeting": "single", "source": null}], "bonus_actions": [], "reactions": [], "legendary_actions": [], "legendary_budget": 0, "passives": [{"name": "Spider Climb", "desc": "The spider can climb difficult surfaces, including upside down on ceilings, without needing to make an ability check.", "source": null}, {"name": "Web Sense", "desc": "While in contact with a web, the spider knows the exact location of any other creature in contact with the same web.", "source": null}, {"name": "Web Walker", "desc": "The spider ignores movement restrictions caused by webbing.", "source": null}], "tags": ["srd", "canon", "beast"]}'::jsonb),
  ('72197dc3-6a44-510a-8ce3-077e1b1e3c01', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000006', 'Troll', '{"name": "Troll", "source_doc": "SRD 2014 (Open5e)", "cr": "5", "type": "giant", "size": "large", "alignment": "chaotic evil", "ac": 15, "ac_detail": "natural armor", "hp": 84, "hit_dice": "8d10+40", "speed": {"walk": 30}, "stats": {"str": 18, "dex": 13, "con": 20, "int": 7, "wis": 9, "cha": 7}, "saves": {}, "skills": {"perception": 2}, "senses": {"passive_perception": 12, "darkvision": 60}, "languages": "Giant", "resistances": "", "immunities": "", "vulnerabilities": "", "condition_immunities": "", "proficiency_bonus": null, "actions": [{"name": "Bite", "desc": "Melee Weapon Attack: +7 to hit, reach 5 ft., one target. Hit: 7 (1d6 + 4) piercing damage.", "targeting": "single", "source": null}, {"name": "Claw", "desc": "Melee Weapon Attack: +7 to hit, reach 5 ft., one target. Hit: 11 (2d6 + 4) slashing damage.", "targeting": "single", "source": null}, {"name": "Multiattack", "desc": "The troll makes three attacks: one with its bite and two with its claws.", "targeting": "single", "source": null}], "bonus_actions": [], "reactions": [], "legendary_actions": [], "legendary_budget": 0, "passives": [{"name": "Keen Smell", "desc": "The troll has advantage on Wisdom (Perception) checks that rely on smell.", "source": null}, {"name": "Regeneration", "desc": "The troll regains 10 hit points at the start of its turn. If the troll takes acid or fire damage, this trait doesn''t function at the start of the troll''s next turn. The troll dies only if it starts its turn with 0 hit points and doesn''t regenerate.", "source": null}, {"name": "Variant: Loathsome Limbs", "desc": "Whenever the troll takes at least 15 slashing damage at one time, roll a d20 to determine what else happens to it:\n\n**1-10:** Nothing else happens.\n**11-14:** One leg is severed from the troll if it has any legs left.\n**15- 18:** One arm is severed from the troll if it has any arms left.\n**19-20:** The troll is decapitated, but the troll dies only if it can''t regenerate. If it dies, so does the severed head.\n\nIf the troll finishes a short or long rest without reattaching a severed limb or head, the part regrows. At that point, the severed part dies. Until then, a severed part acts on the troll''s initiative and has its own action and movement. A severed part has AC 13, 10 hit points, and the troll''s Regeneration trait.\nA **severed leg** is unable to attack and has a speed of 5 feet.\nA **severed arm** has a speed of 5 feet and can make one claw attack on its turn, with disadvantage on the attack roll unless the troll can see the arm and its target. Each time the troll loses an arm, it loses a claw attack.\nIf its head is severed, the troll loses its bite attack and its body is blinded unless the head can see it. The **severed head** has a speed of 0 feet and the troll''s Keen Smell trait. It can make a bite attack but only against a target in its space.\nThe troll''s speed is halved if it''s missing a leg. If it loses both legs, it falls prone. If it has both arms, it can crawl. With only one arm, it can still crawl, but its speed is halved. With no arms or legs, its speed is 0, and it can''t benefit from bonuses to speed.", "source": null}], "tags": ["srd", "canon", "giant"]}'::jsonb),
  ('505b8921-5c19-5089-b739-240b58268692', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000006', 'Mage', '{"name": "Mage", "source_doc": "SRD 2014 (Open5e)", "cr": "6", "type": "humanoid", "size": "medium", "alignment": "any alignment", "ac": 12, "ac_detail": "15 with _mage armor_", "hp": 40, "hit_dice": "9d8", "speed": {"walk": 30}, "stats": {"str": 9, "dex": 14, "con": 11, "int": 17, "wis": 12, "cha": 11}, "saves": {"int": 6, "wis": 4}, "skills": {"arcana": 6, "history": 6}, "senses": {"passive_perception": 11}, "languages": "any four languages", "resistances": "", "immunities": "", "vulnerabilities": "", "condition_immunities": "", "proficiency_bonus": null, "actions": [{"name": "Dagger", "desc": "Melee or Ranged Weapon Attack: +5 to hit, reach 5 ft. or range 20/60 ft., one target. Hit: 4 (1d4 + 2) piercing damage.", "targeting": "single", "source": null}], "bonus_actions": [], "reactions": [], "legendary_actions": [], "legendary_budget": 0, "passives": [{"name": "Spellcasting", "desc": "The mage is a 9th-level spellcaster. Its spellcasting ability is Intelligence (spell save DC 14, +6 to hit with spell attacks). The mage has the following wizard spells prepared:\n\n* Cantrips (at will): fire bolt, light, mage hand, prestidigitation\n* 1st level (4 slots): detect magic, mage armor, magic missile, shield\n* 2nd level (3 slots): misty step, suggestion\n* 3rd level (3 slots): counterspell, fireball, fly\n* 4th level (3 slots): greater invisibility, ice storm\n* 5th level (1 slot): cone of cold", "source": null}], "tags": ["srd", "canon", "humanoid"]}'::jsonb),
  ('12d8fb23-e0d2-56dd-8ec3-582a8f9b56f5', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000006', 'Medusa', '{"name": "Medusa", "source_doc": "SRD 2014 (Open5e)", "cr": "6", "type": "monstrosity", "size": "medium", "alignment": "lawful evil", "ac": 15, "ac_detail": "natural armor", "hp": 127, "hit_dice": "17d8+51", "speed": {"walk": 30}, "stats": {"str": 10, "dex": 15, "con": 16, "int": 12, "wis": 13, "cha": 15}, "saves": {}, "skills": {"deception": 5, "insight": 4, "perception": 4, "stealth": 5}, "senses": {"passive_perception": 14, "darkvision": 60}, "languages": "Common", "resistances": "", "immunities": "", "vulnerabilities": "", "condition_immunities": "", "proficiency_bonus": null, "actions": [{"name": "Longbow", "desc": "Ranged Weapon Attack: +5 to hit, range 150/600 ft., one target. Hit: 6 (1d8 + 2) piercing damage plus 7 (2d6) poison damage.", "targeting": "single", "source": null}, {"name": "Multiattack", "desc": "The medusa makes either three melee attacks - one with its snake hair and two with its shortsword - or two ranged attacks with its longbow.", "targeting": "single", "source": null}, {"name": "Shortsword", "desc": "Melee Weapon Attack: +5 to hit, reach 5 ft., one target. Hit: 5 (1d6 + 2) piercing damage.", "targeting": "single", "source": null}, {"name": "Snake Hair", "desc": "Melee Weapon Attack: +5 to hit, reach 5 ft., one creature. Hit: 4 (1d4 + 2) piercing damage plus 14 (4d6) poison damage.", "targeting": "single", "source": null}], "bonus_actions": [], "reactions": [], "legendary_actions": [], "legendary_budget": 0, "passives": [{"name": "Petrifying Gaze", "desc": "When a creature that can see the medusa''s eyes starts its turn within 30 ft. of the medusa, the medusa can force it to make a DC 14 Constitution saving throw if the medusa isn''t incapacitated and can see the creature. If the saving throw fails by 5 or more, the creature is instantly petrified. Otherwise, a creature that fails the save begins to turn to stone and is restrained. The restrained creature must repeat the saving throw at the end of its next turn, becoming petrified on a failure or ending the effect on a success. The petrification lasts until the creature is freed by the greater restoration spell or other magic.\nUnless surprised, a creature can avert its eyes to avoid the saving throw at the start of its turn. If the creature does so, it can''t see the medusa until the start of its next turn, when it can avert its eyes again. If the creature looks at the medusa in the meantime, it must immediately make the save.\nIf the medusa sees itself reflected on a polished surface within 30 ft. of it and in an area of bright light, the medusa is, due to its curse, affected by its own gaze.", "source": null}], "tags": ["srd", "canon", "monstrosity"]}'::jsonb),
  ('3a9ea0bc-8d30-50c9-a2a8-3cd8828c7efb', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000006', 'Young Red Dragon', '{"name": "Young Red Dragon", "source_doc": "SRD 2014 (Open5e)", "cr": "10", "type": "dragon", "size": "large", "alignment": "chaotic evil", "ac": 18, "ac_detail": "natural armor", "hp": 178, "hit_dice": "17d10+85", "speed": {"walk": 40, "fly": 80, "climb": 40}, "stats": {"str": 23, "dex": 10, "con": 21, "int": 14, "wis": 11, "cha": 19}, "saves": {"dex": 4, "con": 9, "wis": 4, "cha": 8}, "skills": {"perception": 8, "stealth": 4}, "senses": {"passive_perception": 18, "darkvision": 120, "blindsight": 30}, "languages": "Common, Draconic", "resistances": "", "immunities": "fire", "vulnerabilities": "", "condition_immunities": "", "proficiency_bonus": null, "actions": [{"name": "Bite", "desc": "Melee Weapon Attack: +10 to hit, reach 10 ft., one target. Hit: 17 (2d10 + 6) piercing damage plus 3 (1d6) fire damage.", "targeting": "single", "source": null}, {"name": "Claw", "desc": "Melee Weapon Attack: +10 to hit, reach 5 ft., one target. Hit: 13 (2d6 + 6) slashing damage.", "targeting": "single", "source": null}, {"name": "Fire Breath", "desc": "The dragon exhales fire in a 30-foot cone. Each creature in that area must make a DC 17 Dexterity saving throw, taking 56 (16d6) fire damage on a failed save, or half as much damage on a successful one.", "targeting": "area", "source": null}, {"name": "Multiattack", "desc": "The dragon makes three attacks: one with its bite and two with its claws.", "targeting": "single", "source": null}], "bonus_actions": [], "reactions": [], "legendary_actions": [], "legendary_budget": 0, "passives": [], "tags": ["srd", "canon", "dragon"]}'::jsonb),
  ('098d2fc5-629b-585e-910c-6153b63f1004', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000006', 'Adult Red Dragon', '{"name": "Adult Red Dragon", "source_doc": "SRD 2014 (Open5e)", "cr": "17", "type": "dragon", "size": "huge", "alignment": "chaotic evil", "ac": 19, "ac_detail": "natural armor", "hp": 256, "hit_dice": "19d12+133", "speed": {"walk": 40, "fly": 80, "climb": 40}, "stats": {"str": 27, "dex": 10, "con": 25, "int": 16, "wis": 13, "cha": 21}, "saves": {"dex": 6, "con": 13, "wis": 7, "cha": 11}, "skills": {"perception": 13, "stealth": 6}, "senses": {"passive_perception": 23, "darkvision": 120, "blindsight": 60}, "languages": "Common, Draconic", "resistances": "", "immunities": "fire", "vulnerabilities": "", "condition_immunities": "", "proficiency_bonus": null, "actions": [{"name": "Bite", "desc": "Melee Weapon Attack: +14 to hit, reach 10 ft., one target. Hit: 19 (2d10 + 8) piercing damage plus 7 (2d6) fire damage.", "targeting": "single", "source": null}, {"name": "Claw", "desc": "Melee Weapon Attack: +14 to hit, reach 5 ft., one target. Hit: 15 (2d6 + 8) slashing damage.", "targeting": "single", "source": null}, {"name": "Fire Breath", "desc": "The dragon exhales fire in a 60-foot cone. Each creature in that area must make a DC 21 Dexterity saving throw, taking 63 (18d6) fire damage on a failed save, or half as much damage on a successful one.", "targeting": "area", "source": null}, {"name": "Frightful Presence", "desc": "Each creature of the dragon''s choice that is within 120 ft. of the dragon and aware of it must succeed on a DC 19 Wisdom saving throw or become frightened for 1 minute. A creature can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. If a creature''s saving throw is successful or the effect ends for it, the creature is immune to the dragon''s Frightful Presence for the next 24 hours.", "targeting": "area", "source": null}, {"name": "Multiattack", "desc": "The dragon can use its Frightful Presence. It then makes three attacks: one with its bite and two with its claws.", "targeting": "single", "source": null}, {"name": "Tail", "desc": "Melee Weapon Attack: +14 to hit, reach 15 ft., one target. Hit: 17 (2d8 + 8) bludgeoning damage.", "targeting": "single", "source": null}], "bonus_actions": [], "reactions": [], "legendary_actions": [{"name": "Detect", "desc": "The dragon makes a Wisdom (Perception) check.", "targeting": "single", "source": null, "cost": 1}, {"name": "Tail Attack", "desc": "The dragon makes a tail attack.", "targeting": "single", "source": null, "cost": 1}, {"name": "Wing Attack", "desc": "The dragon beats its wings. Each creature within 10 ft. of the dragon must succeed on a DC 22 Dexterity saving throw or take 15 (2d6 + 8) bludgeoning damage and be knocked prone. The dragon can then fly up to half its flying speed.", "targeting": "area", "source": null, "cost": 2}], "legendary_budget": 3, "passives": [{"name": "Legendary Resistance (3/Day)", "desc": "If the dragon fails a saving throw, it can choose to succeed instead.", "source": null}], "tags": ["srd", "canon", "dragon"]}'::jsonb),
  ('f5de4225-f504-5eb6-8609-d19ba68003d1', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000006', 'Lich', '{"name": "Lich", "source_doc": "SRD 2014 (Open5e)", "cr": "21", "type": "undead", "size": "medium", "alignment": "any evil alignment", "ac": 17, "ac_detail": "natural armor", "hp": 135, "hit_dice": "18d8+54", "speed": {"walk": 30}, "stats": {"str": 11, "dex": 16, "con": 16, "int": 20, "wis": 14, "cha": 16}, "saves": {"con": 10, "int": 12, "wis": 9}, "skills": {"arcana": 18, "history": 12, "insight": 9, "perception": 9}, "senses": {"passive_perception": 19, "truesight": 120}, "languages": "Common plus up to five other languages", "resistances": "cold, lightning, necrotic", "immunities": "poison; bludgeoning, piercing, and slashing from nonmagical attacks", "vulnerabilities": "", "condition_immunities": "charmed, exhaustion, frightened, paralyzed, poisoned", "proficiency_bonus": null, "actions": [{"name": "Paralyzing Touch", "desc": "Melee Spell Attack: +12 to hit, reach 5 ft., one creature. Hit: 10 (3d6) cold damage. The target must succeed on a DC 18 Constitution saving throw or be paralyzed for 1 minute. The target can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success.", "targeting": "single", "source": null}], "bonus_actions": [], "reactions": [], "legendary_actions": [{"name": "Cantrip", "desc": "The lich casts a cantrip.", "targeting": "single", "source": null, "cost": 1}, {"name": "Disrupt Life", "desc": "Each non-undead creature within 20 feet of the lich must make a DC 18 Constitution saving throw against this magic, taking 21 (6d6) necrotic damage on a failed save, or half as much damage on a successful one.", "targeting": "single", "source": null, "cost": 3}, {"name": "Frightening Gaze", "desc": "The lich fixes its gaze on one creature it can see within 10 feet of it. The target must succeed on a DC 18 Wisdom saving throw against this magic or become frightened for 1 minute. The frightened target can repeat the saving throw at the end of each of its turns, ending the effect on itself on a success. If a target''s saving throw is successful or the effect ends for it, the target is immune to the lich''s gaze for the next 24 hours.", "targeting": "single", "source": null, "cost": 2}, {"name": "Paralyzing Touch", "desc": "The lich uses its Paralyzing Touch.", "targeting": "single", "source": null, "cost": 2}], "legendary_budget": 3, "passives": [{"name": "Legendary Resistance (3/Day)", "desc": "If the lich fails a saving throw, it can choose to succeed instead.", "source": null}, {"name": "Rejuvenation", "desc": "If it has a phylactery, a destroyed lich gains a new body in 1d10 days, regaining all its hit points and becoming active again. The new body appears within 5 feet of the phylactery.", "source": null}, {"name": "Spellcasting", "desc": "The lich is an 18th-level spellcaster. Its spellcasting ability is Intelligence (spell save DC 20, +12 to hit with spell attacks). The lich has the following wizard spells prepared:\n\n* Cantrips (at will): mage hand, prestidigitation, ray of frost\n* 1st level (4 slots): detect magic, magic missile, shield, thunderwave\n* 2nd level (3 slots): detect thoughts, invisibility, acid arrow, mirror image\n* 3rd level (3 slots): animate dead, counterspell, dispel magic, fireball\n* 4th level (3 slots): blight, dimension door\n* 5th level (3 slots): cloudkill, scrying\n* 6th level (1 slot): disintegrate, globe of invulnerability\n* 7th level (1 slot): finger of death, plane shift\n* 8th level (1 slot): dominate monster, power word stun\n* 9th level (1 slot): power word kill", "source": null}, {"name": "Turn Resistance", "desc": "The lich has advantage on saving throws against any effect that turns undead.", "source": null}], "tags": ["srd", "canon", "undead"]}'::jsonb),
  ('cd6d8d92-cdf3-54b8-8fcf-454974e0d134', '00000000-0000-0000-0000-000000000001', '10000000-0000-0000-0000-000000000006', 'Vampire', '{"name": "Vampire", "source_doc": "SRD 2014 (Open5e)", "cr": "13", "type": "undead", "size": "medium", "alignment": "lawful evil", "ac": 16, "ac_detail": "natural armor", "hp": 144, "hit_dice": "17d8+68", "speed": {"walk": 30}, "stats": {"str": 18, "dex": 18, "con": 18, "int": 17, "wis": 15, "cha": 18}, "saves": {"dex": 9, "wis": 7, "cha": 9}, "skills": {"perception": 7, "stealth": 9}, "senses": {"passive_perception": 17, "darkvision": 120}, "languages": "the languages it knew in life", "resistances": "necrotic; bludgeoning, piercing, and slashing from nonmagical attacks", "immunities": "", "vulnerabilities": "", "condition_immunities": "", "proficiency_bonus": null, "actions": [{"name": "Bite", "desc": "Melee Weapon Attack: +9 to hit, reach 5 ft., one willing creature, or a creature that is grappled by the vampire, incapacitated, or restrained. Hit: 7 (1d6 + 4) piercing damage plus 10 (3d6) necrotic damage. The target''s hit point maximum is reduced by an amount equal to the necrotic damage taken, and the vampire regains hit points equal to that amount. The reduction lasts until the target finishes a long rest. The target dies if this effect reduces its hit point maximum to 0. A humanoid slain in this way and then buried in the ground rises the following night as a vampire spawn under the vampire''s control.", "targeting": "self", "source": null}, {"name": "Charm", "desc": "The vampire targets one humanoid it can see within 30 ft. of it. If the target can see the vampire, the target must succeed on a DC 17 Wisdom saving throw against this magic or be charmed by the vampire. The charmed target regards the vampire as a trusted friend to be heeded and protected. Although the target isn''t under the vampire''s control, it takes the vampire''s requests or actions in the most favorable way it can, and it is a willing target for the vampire''s bite attack.\nEach time the vampire or the vampire''s companions do anything harmful to the target, it can repeat the saving throw, ending the effect on itself on a success. Otherwise, the effect lasts 24 hours or until the vampire is destroyed, is on a different plane of existence than the target, or takes a bonus action to end the effect.", "targeting": "single", "source": null}, {"name": "Children of the Night", "desc": "The vampire magically calls 2d4 swarms of bats or rats, provided that the sun isn''t up. While outdoors, the vampire can call 3d6 wolves instead. The called creatures arrive in 1d4 rounds, acting as allies of the vampire and obeying its spoken commands. The beasts remain for 1 hour, until the vampire dies, or until the vampire dismisses them as a bonus action.", "targeting": "single", "source": null}, {"name": "Multiattack", "desc": "The vampire makes two attacks, only one of which can be a bite attack.", "targeting": "single", "source": null}, {"name": "Unarmed Strike", "desc": "Melee Weapon Attack: +9 to hit, reach 5 ft., one creature. Hit: 8 (1d8 + 4) bludgeoning damage. Instead of dealing damage, the vampire can grapple the target (escape DC 18).", "targeting": "single", "source": null}, {"name": "Shapechanger", "desc": "If the vampire isn''t in sun light or running water, it can use its action to polymorph into a Tiny bat or a Medium cloud of mist, or back into its true form.\nWhile in bat form, the vampire can''t speak, its walking speed is 5 feet, and it has a flying speed of 30 feet. Its statistics, other than its size and speed, are unchanged. Anything it is wearing transforms with it, but nothing it is carrying does. It reverts to its true form if it dies.\nWhile in mist form, the vampire can''t take any actions, speak, or manipulate objects. It is weightless, has a flying speed of 20 feet, can hover, and can enter a hostile creature''s space and stop there. In addition, if air can pass through a space, the mist can do so without squeezing, and it can''t pass through water. It has advantage on Strength, Dexterity, and Constitution saving throws, and it is immune to all nonmagical damage, except the damage it takes from sunlight.", "source": null, "targeting": "single"}], "bonus_actions": [], "reactions": [], "legendary_actions": [{"name": "Bite", "desc": "The vampire makes one bite attack.", "targeting": "single", "source": null, "cost": 2}, {"name": "Unarmed Strike", "desc": "The vampire makes one unarmed strike.", "targeting": "single", "source": null, "cost": 1}, {"name": "Move", "desc": "The vampire moves up to its speed without provoking opportunity attacks.", "targeting": "single", "source": null, "cost": 1}], "legendary_budget": 3, "passives": [{"name": "Legendary Resistance (3/Day)", "desc": "If the vampire fails a saving throw, it can choose to succeed instead.", "source": null}, {"name": "Misty Escape", "desc": "When it drops to 0 hit points outside its resting place, the vampire transforms into a cloud of mist (as in the Shapechanger trait) instead of falling unconscious, provided that it isn''t in sunlight or running water. If it can''t transform, it is destroyed.\nWhile it has 0 hit points in mist form, it can''t revert to its vampire form, and it must reach its resting place within 2 hours or be destroyed. Once in its resting place, it reverts to its vampire form. It is then paralyzed until it regains at least 1 hit point. After spending 1 hour in its resting place with 0 hit points, it regains 1 hit point.", "source": null}, {"name": "Regeneration", "desc": "The vampire regains 20 hit points at the start of its turn if it has at least 1 hit point and isn''t in sunlight or running water. If the vampire takes radiant damage or damage from holy water, this trait doesn''t function at the start of the vampire''s next turn.", "source": null}, {"name": "Spider Climb", "desc": "The vampire can climb difficult surfaces, including upside down on ceilings, without needing to make an ability check.", "source": null}, {"name": "Vampire Weaknesses", "desc": "The vampire has the following flaws:\nForbiddance. The vampire can''t enter a residence without an invitation from one of the occupants.\nHarmed by Running Water. The vampire takes 20 acid damage if it ends its turn in running water.\nStake to the Heart. If a piercing weapon made of wood is driven into the vampire''s heart while the vampire is incapacitated in its resting place, the vampire is paralyzed until the stake is removed.\nSunlight Hypersensitivity. The vampire takes 20 radiant damage when it starts its turn in sunlight. While in sunlight, it has disadvantage on attack rolls and ability checks.", "source": null}], "tags": ["srd", "canon", "undead"]}'::jsonb)
